"use client";

import { useEffect, useRef, useState } from "react";

type KnowledgeSource = "nuke";

interface Message {
  role: "user" | "assistant";
  content: string;
}

interface OpenAIChatProps {
  knowledgeSource: KnowledgeSource;
}

const GREETING =
  "Hi! I can help you explore the Nuke 17.0 reference guide. Try:\n\n" +
  '• "How does the Blur node work?"\n' +
  '• "Find nodes for color grading"\n' +
  '• "Explain the Merge node compositing modes"';

export function OpenAIChat({ knowledgeSource }: OpenAIChatProps) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [streamText, setStreamText] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [justMounted, setJustMounted] = useState(true);
  const abortRef = useRef<AbortController | null>(null);
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Show mount notice briefly then clear
    const t = setTimeout(() => setJustMounted(false), 3000);
    return () => clearTimeout(t);
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, streamText]);

  // Cancel any in-flight request on unmount
  useEffect(() => {
    return () => {
      abortRef.current?.abort();
    };
  }, []);

  async function send() {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { role: "user", content: input.trim() };
    const nextMessages = [...messages, userMsg];
    setMessages(nextMessages);
    setInput("");
    setStreamText("");
    setError(null);
    setIsLoading(true);

    const controller = new AbortController();
    abortRef.current = controller;

    try {
      const res = await fetch("/api/openai-chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: nextMessages,
          knowledgeSource,
        }),
        signal: controller.signal,
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.error ?? `HTTP ${res.status}`);
      }

      const reader = res.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = "";
      let accumulated = "";

      while (true) {
        const { value, done } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop()!; // keep incomplete last chunk

        for (const line of lines) {
          if (!line) continue;
          if (line.startsWith("ERROR: ")) {
            throw new Error(line.slice(7));
          }
          accumulated += line;
          setStreamText(accumulated);
        }
      }

      // Flush any remaining buffer content
      if (buffer) {
        accumulated += buffer;
      }

      setMessages((prev) => [
        ...prev,
        { role: "assistant", content: accumulated || "(no response)" },
      ]);
    } catch (err) {
      if ((err as Error).name !== "AbortError") {
        setError((err as Error).message);
      }
    } finally {
      setStreamText("");
      setIsLoading(false);
      abortRef.current = null;
    }
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      send();
    }
  }

  return (
    <div className="openai-chat-panel">
      <div className="openai-chat-header">
        <span className="openai-chat-title">Nuke Docs Assistant</span>
        <span className="openai-chat-badge">OpenAI Responses API</span>
      </div>

      {justMounted && (
        <div className="openai-chat-notice">
          Conversation cleared — now in OpenAI mode
        </div>
      )}

      {error && (

{justMounted && (
        <div className="openai-chat-notice">
          Conversation cleared — now in OpenAI mode
        </div>
      )}

      {error && (
        <div className="openai-chat-error status-badge" style={{ color: "#dc2626", background: "#fef2f2", margin: "0.5rem 1rem" }}>
          <span>Error: {error}</span>
          <button
            onClick={() => setError(null)}
            style={{ marginLeft: "0.5rem", background: "none", border: "none", cursor: "pointer", color: "#dc2626", fontWeight: 700 }}
          >
            ×
          </button>
        </div>
      )}

      <div className="openai-chat-messages">
        {/* Greeting */}
        <div className="openai-msg assistant">
          <div className="openai-msg-content" style={{ whiteSpace: "pre-wrap" }}>
            {GREETING}
          </div>
        </div>

        {messages.map((msg, i) => (
          <div key={i} className={`openai-msg ${msg.role}`}>
            <div className="openai-msg-content" style={{ whiteSpace: "pre-wrap" }}>
              {msg.content}
            </div>
          </div>
        ))}

        {/* In-flight streaming message */}
        {isLoading && (
          <div className="openai-msg assistant">
            {streamText ? (
              <div className="openai-msg-content" style={{ whiteSpace: "pre-wrap" }}>
                {streamText}
                <span className="openai-cursor" />
              </div>
            ) : (
              <div className="status-badge" style={{ margin: "0.25rem 0" }}>
                <div className="spinner" />
                Searching knowledge base…
              </div>
            )}
          </div>
        )}

        <div ref={bottomRef} />
      </div>

      <div className="openai-chat-input-row">
        <textarea
          className="openai-chat-input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask about Nuke nodes, compositing, VFX…"
          rows={2}
          disabled={isLoading}
        />
        <button
          className={`openai-chat-send source-btn${isLoading ? "" : " active"}`}
          onClick={send}
          disabled={isLoading || !input.trim()}
          style={{ pointerEvents: isLoading ? "none" : "auto" }}
        >
          {isLoading ? <div className="spinner" /> : "Send"}
        </button>
      </div>
    </div>
  );
}

"use client";

export interface SearchHit {
  arxiv_id: string;
  title: string;
  authors?: string;
  abstract?: string;
  published_date?: string;
  pdf_url?: string;
  score: number;
  section_name?: string;
  chunk_text?: string;
  // Nuke docs fields
  url?: string;
  nuke_node_name?: string;
  section?: string;
}

export function PaperCard({ hit }: { hit: SearchHit }) {
  return (
    <div className="paper-card">
      <h4>{hit.title}</h4>
      <div className="meta">
        {hit.authors && (
          <span>
            {hit.authors.split(",").slice(0, 2).join(", ")}
            {hit.authors.split(",").length > 2 ? " et al." : ""}
          </span>
        )}
        {hit.published_date && <span>{hit.published_date.slice(0, 10)}</span>}
        {hit.section_name && <span>{hit.section_name}</span>}
        <span>score: {hit.score.toFixed(3)}</span>
      </div>
      {hit.abstract && <p className="abstract">{hit.abstract}</p>}
      {hit.chunk_text && !hit.abstract && <p className="abstract">{hit.chunk_text}</p>}
      {hit.pdf_url && (
        <a href={hit.pdf_url} target="_blank" rel="noopener noreferrer">
          View PDF →
        </a>
      )}
    </div>
  );
}

export function PaperResults({ hits }: { hits: SearchHit[] }) {
  if (!hits || hits.length === 0) {
    return <p style={{ fontSize: "0.85rem", color: "#64748b" }}>No papers found.</p>;
  }
  return (
    <div>
      <p style={{ fontSize: "0.78rem", color: "#64748b", marginBottom: "0.5rem" }}>
        Found {hits.length} paper{hits.length !== 1 ? "s" : ""}
      </p>
      {hits.slice(0, 5).map((hit) => (
        <PaperCard key={`${hit.arxiv_id}-${hit.chunk_text?.slice(0, 10)}`} hit={hit} />
      ))}
    </div>
  );
}

export function NukeResultCard({ hit }: { hit: SearchHit }) {
  const label = hit.nuke_node_name ?? hit.url?.split("/").at(-1)?.replace(".html", "") ?? "Node";
  const sectionLabel = hit.section ?? hit.section_name;

  return (
    <div className="nuke-card">
      <div className="nuke-card-header">
        <span className="nuke-badge">Nuke</span>
        <h4>{label}</h4>
      </div>
      <div className="meta">
        {sectionLabel && <span>{sectionLabel}</span>}
        <span>score: {hit.score.toFixed(3)}</span>
      </div>
      {hit.chunk_text && <p className="abstract">{hit.chunk_text}</p>}
      {hit.url && (
        <a href={hit.url} target="_blank" rel="noopener noreferrer">
          View in Nuke Docs →
        </a>
      )}
    </div>
  );
}

export function NukeResults({ hits }: { hits: SearchHit[] }) {
  if (!hits || hits.length === 0) {
    return (
      <p style={{ fontSize: "0.85rem", color: "#64748b" }}>
        No Nuke docs found. Run the <code>nuke_docs_ingestion</code> DAG first.
      </p>
    );
  }
  return (
    <div>
      <p style={{ fontSize: "0.78rem", color: "#64748b", marginBottom: "0.5rem" }}>
        Found {hits.length} Nuke doc{hits.length !== 1 ? "s" : ""}
      </p>
      {hits.slice(0, 5).map((hit, i) => (
        <NukeResultCard key={`${hit.url ?? i}-${hit.chunk_text?.slice(0, 10)}`} hit={hit} />
      ))}
    </div>
  );
}

"use client";

import { useCopilotAction, useCopilotReadable } from "@copilotkit/react-core";
import { CopilotSidebar } from "@copilotkit/react-ui";
import { useState } from "react";
import { NukeResults, PaperResults, type SearchHit } from "./PaperCard";
import { AgentSteps } from "./AgentSteps";

const API_BASE = "";

type KnowledgeSource = "arxiv" | "nuke";

interface RAGCopilotProps {
  knowledgeSource: KnowledgeSource;
  onKnowledgeSourceChange: (src: KnowledgeSource) => void;
}

export function RAGCopilot({ knowledgeSource, onKnowledgeSourceChange }: RAGCopilotProps) {
  const [lastSearchQuery, setLastSearchQuery] = useState("");
  const [lastSearchCount, setLastSearchCount] = useState(0);

  useCopilotReadable({
    description: "Current knowledge source and session state",
    value: JSON.stringify({
      knowledge_source: knowledgeSource,
      knowledge_source_label: knowledgeSource === "nuke" ? "Nuke 17.0 Reference" : "arXiv CS.AI Papers",
      last_search:
        lastSearchCount > 0
          ? `"${lastSearchQuery}" → ${lastSearchCount} results`
          : "none",
    }),
  });

  // Generative UI: LLM calls this when it infers the user wants to switch sources
  useCopilotAction({
    name: "set_knowledge_source",
    description:
      "Switch the active knowledge source. Call this when the user's question is clearly " +
      "about Nuke VFX software (nodes, compositing, reference guide) to switch to 'nuke', " +
      "or about AI/ML research papers to switch to 'arxiv'.",
    parameters: [
      {
        name: "source",
        type: "string",
        description: "Knowledge source to activate: 'arxiv' or 'nuke'",
        required: true,
      },
      {
        name: "reason",
        type: "string",
        description: "One-sentence reason for switching",
        required: false,
      },
    ],
    handler: async ({ source, reason }: { source: string; reason?: string }) => {
      const validated = source === "nuke" ? "nuke" : "arxiv";
      onKnowledgeSourceChange(validated);
      return { active: validated, reason };
    },
    render: ({
      status,
      result,
    }: {
      status: string;
      result?: { active: string; reason?: string };
    }) => {
      const active = result?.active ?? knowledgeSource;
      const label = active === "nuke" ? "Nuke 17.0 Reference" : "arXiv CS.AI Papers";
      const icon = active === "nuke" ? "🎬" : "📄";
      if (status === "executing") {
        return (
          <div className="status-badge">
            <div className="spinner" />
            Switching knowledge source…
          </div>
        );
      }
      return (
        <div className="source-switch-result">
          <span className={`source-chip ${active}`}>
            {icon} {label}
          </span>
          {result?.reason && (
            <p className="source-switch-reason">{result.reason}</p>
          )}
        </div>
      );
    },
  });

  useCopilotAction({
    name: "search_papers",
    description:
      "Search the active knowledge base using hybrid BM25 + vector search. " +
      "Use when the user wants to find, browse, or list results on a topic. " +
      "Searches arXiv papers when knowledge_source is 'arxiv', " +
      "or Nuke documentation when knowledge_source is 'nuke'.",
    parameters: [
      {
        name: "query",
        type: "string",
        description: "Search query — topic, keyword, node name, or paper title",
        required: true,
      },
      {
        name: "size",
        type: "number",
        description: "Number of results to return (default: 5, max: 10)",
        required: false,
      },
    ],
    handler: async ({ query, size = 5 }: { query: string; size?: number }) => {
      const res = await fetch(`${API_BASE}/api/v1/hybrid-search/`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          query,
          size: Math.min(size, 10),
          use_hybrid: true,

handler: async ({ query, size = 5 }: { query: string; size?: number }) => {
      const res = await fetch(`${API_BASE}/api/v1/hybrid-search/`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          query,
          size: Math.min(size, 10),
          use_hybrid: true,
          knowledge_source: knowledgeSource,
        }),
      });
      if (!res.ok) throw new Error(`Search failed: ${res.status}`);
      const data = await res.json();
      const hits: SearchHit[] = data.hits ?? [];
      setLastSearchQuery(query);
      setLastSearchCount(hits.length);
      return { hits, knowledge_source: knowledgeSource };
    },
    render: ({
      status,
      result,
    }: {
      status: string;
      result?: { hits: SearchHit[]; knowledge_source: string };
    }) => {
      if (status === "executing") {
        const label = knowledgeSource === "nuke" ? "Nuke docs" : "arXiv papers";
        return (
          <div className="status-badge">
            <div className="spinner" />
            Searching {label}…
          </div>
        );
      }
      const hits = Array.isArray(result?.hits) ? result.hits : [];
      return result?.knowledge_source === "nuke" ? (
        <NukeResults hits={hits} />
      ) : (
        <PaperResults hits={hits} />
      );
    },
  });

  useCopilotAction({
    name: "ask_question",
    description:
      "Ask a question and get an AI-powered answer grounded in the active knowledge base. " +
      "Use when the user wants a direct answer, explanation, or summary. " +
      "Works for both arXiv research questions and Nuke VFX technical questions.",
    parameters: [
      {
        name: "query",
        type: "string",
        description: "The question to answer",
        required: true,
      },
    ],
    handler: async ({ query }: { query: string }) => {
      const res = await fetch(`${API_BASE}/api/v1/ask`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          query,
          top_k: 3,
          use_hybrid: true,
          knowledge_source: knowledgeSource,
        }),
      });
      if (!res.ok) throw new Error(`Ask failed: ${res.status}`);
      return await res.json();
    },
    render: ({
      status,
      result,
    }: {
      status: string;
      result?: { answer: string; sources: string[]; chunks_used: number; search_mode: string };
    }) => {
      if (status === "executing") {
        return (
          <div className="status-badge">
            <div className="spinner" />
            Retrieving context and generating answer…
          </div>
        );
      }
      if (!result) return <></>;
      return (
        <div className="agent-steps">
          <div className="answer-block">{result.answer}</div>
          {result.sources?.length > 0 && (
            <div className="sources-list">
              <p style={{ fontSize: "0.75rem", color: "#64748b", marginTop: "0.5rem" }}>
                Sources ({result.chunks_used} chunks · {result.search_mode}):
              </p>
              {result.sources.slice(0, 3).map((src, i) => (
                <a key={i} href={src} target="_blank" rel="noopener noreferrer">
                  {src.replace(/^https?:\/\//, "").split("/").slice(0, 4).join("/")}
                </a>
              ))}
            </div>
          )}
        </div>
      );
    },
  });

  useCopilotAction({
    name: "ask_agentic",
    description:
      "Use the full agentic RAG pipeline with LangGraph reasoning: guardrails, document grading, " +
      "query rewriting, and multi-step retrieval. Use for complex or nuanced questions " +
      "that may require multiple retrieval attempts. Works with both arXiv and Nuke knowledge sources.",
    parameters: [
      {
        name: "query",
        type: "string",
        description: "Complex question for agentic reasoning",
        required: true,
      },
    ],

parameters: [
      {
        name: "query",
        type: "string",
        description: "Complex question for agentic reasoning",
        required: true,
      },
    ],
    handler: async ({ query }: { query: string }) => {
      const res = await fetch(`${API_BASE}/api/v1/ask-agentic`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          query,
          top_k: 3,
          use_hybrid: true,
          knowledge_source: knowledgeSource,
        }),
      });
      if (!res.ok) throw new Error(`Agentic ask failed: ${res.status}`);
      return await res.json();
    },
    render: ({
      status,
      result,
    }: {
      status: string;
      result?: { answer: string; reasoning_steps: string[]; sources: string[]; retrieval_attempts: number };
    }) => {
      if (status === "executing") {
        return (
          <div className="status-badge">
            <div className="spinner" />
            Running agentic reasoning pipeline…
          </div>
        );
      }
      if (!result) return <></>;
      return (
        <AgentSteps
          steps={result.reasoning_steps ?? []}
          answer={result.answer}
          sources={result.sources ?? []}
        />
      );
    },
  });

  const greeting =
    knowledgeSource === "nuke"
      ? "Hi! I can help you explore the Nuke 17.0 reference guide. Try:\n\n" +
        '• "How does the Blur node work?"\n' +
        '• "Find nodes for color grading"\n' +
        '• "Explain the Merge node compositing modes"'
      : "Hi! I can help you explore AI and ML research papers. Try:\n\n" +
        '• "What are vision transformers?"\n' +
        '• "Find papers on diffusion models"\n' +
        '• "Explain RLHF with citations"';

  return (
    <CopilotSidebar
      defaultOpen={true}
      labels={{
        title:
          knowledgeSource === "nuke"
            ? "Nuke Docs Assistant"
            : "arXiv Research Assistant",
        initial: greeting,
      }}
      instructions={
        "You are an AI assistant with access to two knowledge bases: " +
        "(1) arXiv CS.AI research papers and (2) Foundry Nuke 17.0 VFX software documentation. " +
        `The currently active knowledge source is: ${knowledgeSource === "nuke" ? "Nuke 17.0 Reference" : "arXiv CS.AI Papers"}. ` +
        "When a user's question clearly relates to Nuke VFX software (nodes, compositing, effects), " +
        "call set_knowledge_source with source='nuke' BEFORE answering. " +
        "When it relates to AI/ML research, call set_knowledge_source with source='arxiv'. " +
        "Then use ask_question for direct answers, search_papers to browse results, " +
        "or ask_agentic for complex multi-step reasoning. " +
        "Always cite sources when available."
      }
    />
  );
}

