                    metadata={"prompt_source": source},
                )

        # Validate LLM output
        if not result or not result.rewritten_query:
            raise ValueError("LLM failed to return valid structured output for query rewriting")

        rewritten_query = result.rewritten_query.strip()
        if not rewritten_query:
            raise ValueError("LLM returned empty rewritten query")

        reasoning = result.reasoning

        llm_duration = time.time() - llm_start
        logger.info(
            f"Query rewritten in {llm_duration:.2f}s: "
            f"'{original_question[:50]}...' -> '{rewritten_query[:50]}...'"
        )
        logger.debug(f"Rewriting reasoning: {reasoning}")

    except Exception as e:
        logger.error(f"Failed to rewrite query using LLM: {e}")
        logger.warning("Falling back to simple keyword expansion")
        # Fallback to simple expansion if LLM fails
        rewritten_query = f"{original_question} nuke vfx compositing documentation"
        reasoning = "Fallback: Simple keyword expansion due to LLM error"

    # Update span with rewriting result
    if span:
        execution_time = (time.time() - start_time) * 1000
        runtime.context.langfuse_tracer.end_span(
            span,
            output={
                "rewritten_query": rewritten_query,
                "reasoning": reasoning,
                "original_query": original_question,
            },
            metadata={
                "execution_time_ms": execution_time,
                "original_length": len(original_question),
                "rewritten_length": len(rewritten_query),
                "llm_duration_seconds": llm_duration if 'llm_duration' in locals() else None,
            },
        )

    return {
        "messages": [HumanMessage(content=rewritten_query)],
        "rewritten_query": rewritten_query,
    }

terraform {
  backend "s3" {
    # IMPORTANT: Copy the bucket name from `terraform output state_bucket_name`
    # after running bootstrap. Variable interpolation is NOT allowed here.
    bucket         = "REPLACE_WITH_BUCKET_NAME"
    key            = "dev/infra.tfstate"
    region         = "us-east-1"
    dynamodb_table = "rag-terraform-lock"
    encrypt        = true
  }
}

terraform {
  required_version = ">= 1.6"
  required_providers {
    aws = { source = "hashicorp/aws", version = "~> 5.0" }
  }
}

provider "aws" {
  region = var.aws_region
}

module "networking" {
  source = "../../modules/networking"

  name_prefix     = var.name_prefix
  vpc_cidr        = "10.0.0.0/16"
  subnet_cidr_az1 = "10.0.1.0/24"
  subnet_cidr_az2 = "10.0.2.0/24"
}

module "security" {
  source = "../../modules/security"

  name_prefix = var.name_prefix
  vpc_id      = module.networking.vpc_id
  vpc_cidr    = module.networking.vpc_cidr
  admin_cidr  = var.admin_cidr
}

module "iam" {
  source      = "../../modules/iam"
  name_prefix = var.name_prefix
}

module "ec2" {
  source = "../../modules/ec2"

  instance_name         = "${var.name_prefix}-infra"
  instance_type         = "t3.xlarge"
  volume_gb             = 80
  subnet_id             = module.networking.subnet_id_az1
  security_group_ids    = [module.security.sg_ssh_id, module.security.sg_app_id]
  instance_profile_name = module.iam.instance_profile_name
  key_name              = var.key_name
  public_key_content    = var.public_key_content

  user_data_rendered = templatefile("${path.module}/user_data.sh.tpl", {
    aws_region           = var.aws_region
    github_owner         = var.github_owner
    github_repo          = var.github_repo
    orchestrator_profile = var.orchestrator_profile
    github_pat_ssm_name  = var.github_pat_ssm_name
    env_ssm_name         = var.env_ssm_name
  })
}

# Guard: prevent accidental replacement (new private IP cascades to api+ui layers)
resource "null_resource" "infra_destroy_guard" {
  triggers = { instance_id = module.ec2.instance_id }

  lifecycle {
    prevent_destroy = true
  }
}

output "vpc_id"                { value = module.networking.vpc_id }
output "vpc_cidr"              { value = module.networking.vpc_cidr }
output "subnet_id_az1"         { value = module.networking.subnet_id_az1 }
output "subnet_id_az2"         { value = module.networking.subnet_id_az2 }
output "sg_ssh_id"             { value = module.security.sg_ssh_id }
output "sg_app_id"             { value = module.security.sg_app_id }
output "sg_alb_id"             { value = module.security.sg_alb_id }
output "infra_private_ip"      { value = module.ec2.private_ip }
output "infra_public_ip"       { value = module.ec2.public_ip }
output "infra_instance_id"     { value = module.ec2.instance_id }
output "instance_profile_name" { value = module.iam.instance_profile_name }

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "name_prefix" {
  description = "Prefix for all resource names"
  type        = string
  default     = "rag"
}

variable "admin_cidr" {
  description = "Your public IP in CIDR notation for SSH and admin port access. Example: 203.0.113.5/32"
  type        = string
}

variable "key_name" {
  description = "EC2 key pair name"
  type        = string
  default     = "rag-key"
}

variable "public_key_content" {
  description = "Contents of your SSH public key file"
  type        = string
}

variable "github_owner" {
  description = "GitHub username or org that owns the repo"
  type        = string
}

variable "github_repo" {
  description = "GitHub repo name (without owner prefix)"
  type        = string
  default     = "GenerativeAI"
}

variable "orchestrator_profile" {
  description = "docker compose profile to activate: prefect | airflow | dagster"
  type        = string
  default     = "prefect"
}

variable "github_pat_ssm_name" {
  description = "SSM parameter name for GitHub PAT (for private repos). Leave empty for public repos."
  type        = string
  default     = ""
}

variable "env_ssm_name" {
  description = "SSM parameter name storing the .env file contents"
  type        = string
  default     = "/rag/env"
}

terraform {
  backend "s3" {
    bucket         = "REPLACE_WITH_BUCKET_NAME"
    key            = "dev/api.tfstate"
    region         = "us-east-1"
    dynamodb_table = "rag-terraform-lock"
    encrypt        = true
  }
}

terraform {
  required_version = ">= 1.6"
  required_providers {
    aws = { source = "hashicorp/aws", version = "~> 5.0" }
  }
}

provider "aws" {
  region = var.aws_region
}

data "terraform_remote_state" "infra" {
  backend = "s3"
  config = {
    bucket         = var.state_bucket
    key            = "dev/infra.tfstate"
    region         = var.aws_region
    dynamodb_table = "rag-terraform-lock"
  }
}

locals {
  infra = data.terraform_remote_state.infra.outputs
}

module "ec2" {
  source = "../../modules/ec2"

  instance_name         = "${var.name_prefix}-api"
  instance_type         = "t3.large"
  volume_gb             = 60
  subnet_id             = local.infra.subnet_id_az1
  security_group_ids    = [local.infra.sg_ssh_id, local.infra.sg_app_id]
  instance_profile_name = local.infra.instance_profile_name
  key_name              = var.key_name
  public_key_content    = var.public_key_content

  user_data_rendered = templatefile("${path.module}/user_data.sh.tpl", {
    aws_region          = var.aws_region
    github_owner        = var.github_owner
    github_repo         = var.github_repo
    github_pat_ssm_name = var.github_pat_ssm_name
    env_ssm_name        = var.env_ssm_name
    infra_private_ip    = local.infra.infra_private_ip
  })
}
